// EDTMRS - App Root
import React, { useState, useCallback } from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './hooks/useAuth';
import { useWebSocket } from './hooks/useWebSocket';
import Sidebar from './components/Sidebar';
import AlertPopup from './components/AlertPopup';
import LoginPage from './pages/LoginPage';
import DashboardPage from './pages/DashboardPage';
import DevicesPage from './pages/DevicesPage';
import EndpointsPage from './pages/EndpointsPage';
import AlertsPage from './pages/AlertsPage';
import PolicyPage from './pages/PolicyPage';

function ProtectedLayout() {
  const { user } = useAuth();
  const [liveEvents, setLiveEvents]   = useState([]);
  const [popups, setPopups]           = useState([]);
  const [alertCount, setAlertCount]   = useState(0);

  const handleWsMessage = useCallback((msg) => {
    if (msg.type === 'device_event' || msg.type === 'device_alert') {
      const data = msg.data;

      if (msg.type === 'device_event') {
        setLiveEvents((prev) => [...prev.slice(-49), data]);
      }

      if (msg.type === 'device_alert') {
        const id = Date.now();
        setPopups((prev) => [...prev.slice(-3), { ...data, _id: id }]);
        setAlertCount((c) => c + 1);
      }
    }
  }, []);

  useWebSocket(handleWsMessage);

  if (!user) return <Navigate to="/login" replace />;

  return (
    <div className="flex min-h-screen bg-[#0a0e1a]">
      <Sidebar alertCount={alertCount} />

      {/* Main content */}
      <main className="flex-1 ml-60 p-6 min-h-screen overflow-y-auto">
        <Routes>
          <Route path="/"          element={<DashboardPage liveEvents={liveEvents} />} />
          <Route path="/devices"   element={<DevicesPage   liveEvents={liveEvents} />} />
          <Route path="/endpoints" element={<EndpointsPage liveEvents={liveEvents} />} />
          <Route path="/alerts"    element={<AlertsPage    liveEvents={liveEvents} onAlertCountChange={setAlertCount} />} />
          <Route path="/policy"    element={<PolicyPage />} />
          <Route path="*"          element={<Navigate to="/" replace />} />
        </Routes>
      </main>

      {/* Real-time alert popups */}
      <div className="fixed bottom-5 right-5 z-50 space-y-3">
        {popups.map((popup) => (
          <AlertPopup
            key={popup._id}
            alert={popup}
            onClose={() => setPopups((p) => p.filter((x) => x._id !== popup._id))}
          />
        ))}
      </div>
    </div>
  );
}

function AppRoutes() {
  const { loading } = useAuth();
  if (loading) return (
    <div className="min-h-screen bg-[#0a0e1a] flex items-center justify-center">
      <div className="w-8 h-8 border-2 border-blue-500/30 border-t-blue-400 rounded-full animate-spin" />
    </div>
  );
  return (
    <Routes>
      <Route path="/login" element={<LoginPage />} />
      <Route path="/*"     element={<ProtectedLayout />} />
    </Routes>
  );
}

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <AppRoutes />
      </BrowserRouter>
    </AuthProvider>
  );
}
